import { GoogleGenAI } from "@google/genai";
import { SystemMode } from "../types";
import { SYSTEM_DEFINITION } from "../constants";

const getClient = () => {
    const apiKey = process.env.API_KEY;
    if (!apiKey) {
        throw new Error("API_KEY is not defined");
    }
    return new GoogleGenAI({ apiKey });
};

export const generateUltimatePrompt = async (
    topic: string, 
    mode: SystemMode,
    referenceImage?: { data: string, mimeType: string } | null
): Promise<string> => {
    try {
        const client = getClient();

        let systemInstruction = `
${SYSTEM_DEFINITION}

You are the UltraPromptEngine. 
Your task is to execute the "generate_ultimate_prompt" function for the user's input.
You must adopt the persona of the Cognitive Limit System v3.0 fully.

CURRENT MODE: ${mode}

Output Format:
Return the final "Ultimate Prompt" formatted in Markdown.
**IMPORTANT: The entire output must be in Simplified Chinese (简体中文).**
Start with the # [TRANSCENDENT_ROLE] section.
Do not include your internal monologue in the final output, but you must PERFORM the internal processing to ensure high quality.
Ensure the output follows the 💠 OUTPUT_ARCHITECTURE_V3 strictly.

[ASPECT RATIO PROTOCOL]
When generating image prompts or descriptions:
1. DEFAULT: You must set the aspect ratio to **16:9** (--ar 16:9) by default.
2. OVERRIDE: If the user's input explicitly contains a different aspect ratio request (e.g., "1:1", "3:4", "vertical", "portrait"), you must strictly adhere to the user's request.
`;

        if (referenceImage) {
            systemInstruction += `
\n\n[VISUAL REFERENCE INJECTED]
An image has been provided as a style reference.
You MUST analyze this image for:
1. Visual Style (e.g., Cyberpunk, Minimalist, Baroque, etc.)
2. Tonality/Atmosphere (e.g., Melancholic, Vibrant, Ethereal)
3. Spatial Structure/Composition
INTEGRATE these visual elements deeply into the generated prompt content. The result should reflect the "vibe" and aesthetic of this reference image while addressing the user's topic.
`;
        }

        const parts: any[] = [];

        if (referenceImage) {
            parts.push({
                inlineData: {
                    mimeType: referenceImage.mimeType,
                    data: referenceImage.data
                }
            });
        }

        parts.push({
            text: `请为以下主题生成终极提示词（请使用简体中文输出）: "${topic}"`
        });

        const response = await client.models.generateContent({
            model: 'gemini-3-pro-preview', // Using powerful model for reasoning
            contents: {
                parts: parts
            },
            config: {
                systemInstruction: systemInstruction,
                temperature: 0.8, // High creativity
                thinkingConfig: { thinkingBudget: 4096 } // Allow for deep thought simulation
            }
        });

        return response.text || "系统故障：认知坍缩。请重试。";
    } catch (error) {
        console.error("Cognitive Engine Error:", error);
        throw error;
    }
};

export const extractTextFromImage = async (
    base64Data: string, 
    mimeType: string
): Promise<string> => {
    try {
        const client = getClient();
        const response = await client.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: {
                parts: [
                    {
                        inlineData: {
                            mimeType: mimeType,
                            data: base64Data
                        }
                    },
                    {
                        text: "OCR Task: Extract all text from this image directly. Return ONLY the extracted text content without any markdown formatting, explanations, or labels."
                    }
                ]
            }
        });
        return response.text || "";
    } catch (error) {
        console.error("OCR Error:", error);
        throw error;
    }
};
